import{_ as a,o as d,c as n,a2 as s}from"./chunks/framework.BnBoz4Zl.js";const b=JSON.parse('{"title":"附录 C 历史踩坑与故障排查","description":"本附录只记录可迁移的方法，不展示内部项目、系统、人员和数据。","frontmatter":{},"headers":[],"relativePath":"bluebook/附录/附录 C 历史踩坑与故障排查/index.md","filePath":"bluebook/附录/附录 C 历史踩坑与故障排查/index.md","lastUpdated":1784100816000}'),e={name:"bluebook/附录/附录 C 历史踩坑与故障排查/index.md"};function l(p,t,r,i,o,c){return d(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="附录-c-历史踩坑与故障排查" tabindex="-1">附录 C 历史踩坑与故障排查 <a class="header-anchor" href="#附录-c-历史踩坑与故障排查" aria-label="Permalink to &quot;附录 C 历史踩坑与故障排查&quot;">​</a></h1><p>本附录只记录可迁移的方法，不展示内部项目、系统、人员和数据。</p><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th><th>安全处理</th></tr></thead><tbody><tr><td>AI 写得很顺，但事实不对</td><td>输入缺口被模型补全</td><td>先建事实与来源清单；无依据内容标记待确认</td></tr><tr><td>一次批量处理后错误很多</td><td>没有先做最小样本</td><td>先处理一页、三条或少量文件，验收后再扩大</td></tr><tr><td>文件整理后找不到原件</td><td>直接移动、覆盖或删除</td><td>原始目录只读，先输出操作预览和冲突清单</td></tr><tr><td>“最终版”有多个</td><td>只看文件名，没有审批依据</td><td>用确认、签署、日期和版本关系判断，状态不明先保留</td></tr><tr><td>自动化没有输出</td><td>任务仍在运行、路径错误或静默失败</td><td>检查进程、日志、输入和输出目录，不盲目重复启动</td></tr><tr><td>自动化重复写入</td><td>没有幂等标识或同类任务预检</td><td>运行前检查批次和目标记录，重复项跳过并记录</td></tr><tr><td>信息摘要与原文不一致</td><td>只使用二手摘要或未核验来源</td><td>回到原始来源核对主体、日期和关键事实</td></tr><tr><td>数据图表结论偏差</td><td>口径不一致、过滤小样本或混淆因果</td><td>固化口径，显示样本和限制，结论绑定证据</td></tr><tr><td>知识库越来越大却找不到</td><td>只有收藏，没有来源页和使用目的</td><td>一项来源一条记录，知识点关联具体任务</td></tr><tr><td>远程任务权限不足</td><td>目录、账号或网络边界未预检</td><td>在本地先测试最小权限，远程不扩大授权</td></tr><tr><td>多 Agent 输出互相矛盾</td><td>角色边界和共享字段不一致</td><td>定义输入输出契约，冲突并列交人工确认</td></tr><tr><td>构建成功但网站仍是旧内容</td><td>只更新源码，未同步公开构建仓库</td><td>构建后检查部署提交和线上目标页面</td></tr></tbody></table><h2 id="通用排查顺序" tabindex="-1">通用排查顺序 <a class="header-anchor" href="#通用排查顺序" aria-label="Permalink to &quot;通用排查顺序&quot;">​</a></h2><ol><li>先确认目标和预期结果。</li><li>再检查输入、路径、版本和权限。</li><li>查看任务状态、日志和中间产物。</li><li>用最小样本复现问题。</li><li>只修改一个变量并重新验证。</li><li>修复后补充检查表或自动测试，避免重复踩坑。</li></ol><h2 id="可复制故障报告" tabindex="-1">可复制故障报告 <a class="header-anchor" href="#可复制故障报告" aria-label="Permalink to &quot;可复制故障报告&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>任务目标：</span></span>
<span class="line"><span>预期结果：</span></span>
<span class="line"><span>实际现象：</span></span>
<span class="line"><span>首次出现时间：</span></span>
<span class="line"><span>输入和工作目录：</span></span>
<span class="line"><span>已确认的权限：</span></span>
<span class="line"><span>最后一个成功步骤：</span></span>
<span class="line"><span>错误信息或日志位置：</span></span>
<span class="line"><span>已经尝试的操作：</span></span>
<span class="line"><span>禁止执行的操作：删除、覆盖、扩大权限、重复批量启动</span></span></code></pre></div>`,7)])])}const _=a(e,[["render",l]]);export{b as __pageData,_ as default};
